const Q_IRK_2010=[{"id": "objective>IRK>2010>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The revelation of the glorious Qur'an started with a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">command</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">declaration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Iqrah\" \"Read\" or \"Recite\". This is a direct command from Allah to the prophet through Angel Jibril. Q96:1 </div>", "topic": "THE QUR’AN AND HADITH – REVELATION OF THE GLORIOUS QUR’AN : HIS REACTION TO THE FIRST REVELATION AND ITS IMPORTANCE"}, {"id": "objective>IRK>2010>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet Muhammad's (SAW) answer to Angel Jibril when he was asked to recite was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">\"I am not a scholar\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"I am not a judge\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"I cannot read\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"I cannot preach\"</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When Angel Jibril asked Prophet Muhammad (SAW) to recite, his response was 'I cannot read'. This is because the Prophet was unlettered, meaning he could not read or write. The other options do not accurately reflect the Prophet's response.</div>", "topic": "THE QUR’AN AND HADITH – REVELATION OF THE GLORIOUS QUR’AN : HIS REACTION TO THE FIRST REVELATION AND ITS IMPORTANCE"}, {"id": "objective>IRK>2010>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Angel Jibril asked the Prophet (SAW) to read during the event of the first revelation</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">four times </div>", "<div style=\"font-family:Cambria;font-size:17px;\">three times</div>", "<div style=\"font-family:Cambria;font-size:17px;\">twice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">once</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Angel Jibril asked the Prophet (SAW) to read three times during the event of the first revelation. After each of the Prophet's responses that he could not read, the Angel repeated the command to read. This happened three times before the Angel finally read the verses to the Prophet.</div>", "topic": "THE QUR’AN AND HADITH – REVELATION OF THE GLORIOUS QUR’AN : HIS REACTION TO THE FIRST REVELATION AND ITS IMPORTANCE"}, {"id": "objective>IRK>2010>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"No falsehood can approach it, from before or behind it, it is sent down by One full of wisdom, worthy of all praise.\" The verse above is the same as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The clear explanation i presented here <img src=\"2010/option4a.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "PROOF OF THE DIVINE AUTHENTICITY OF THE GLORIOUS QUR'AN : DIVINE PRESERVATION OF THE GLORIOUS QUR'AN"}, {"id": "objective>IRK>2010>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many Caliphs did the Glorious Qur'an pass through before its standardization?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Six </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Four</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Three </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Two</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Umar suggested compilation of Quran to Abu Bakr and Othman standardize it.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : RECORDING, COMPILATION AND STANDARDIZATION OF THE GLORIOUS QUR’AN"}, {"id": "objective>IRK>2010>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Divine inspiration was employed in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">arrangement of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compilation of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standardization of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">memorization of the Glorious Qur'an</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Arrangement of Glorious Quran was done by the prophet who received Divine inspiration.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : COMPLETE ARRANGEMENT"}, {"id": "objective>IRK>2010>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The authenticity of the Glorious Qur'an has been proven by empirical evidence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dredging sea water to dams</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stages of growth of human embryo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development of nuclear technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development of solar technology</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The authenticity of the Glorious Qur'an has been proven by empirical evidence of stages of growth of human embryo. The Qur'an contains verses that accurately describe the development of the human embryo, which were unknown at the time of its revelation and have only been discovered by modern science.</div>", "topic": "PROOF OF THE DIVINE AUTHENTICITY OF THE GLORIOUS QUR'AN : UNIQUENESS OF THE GLORIOUS QUR'AN"}, {"id": "objective>IRK>2010>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major peculiarity between the Makkan and Madinan Suwar of the Glorious Qur'an is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Makkan Suwar are historical while Madinan Suwar are theoretical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Makkan Suwar are meant for daily rituals while Madinan Suwar are for commercial transactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Makkan Suwar are purely to people of Makkan while the Madinan Suwar addresses the people of Madina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Makkan Suwar are short and poetic while the Madinan Suwar are longer and generic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One major peculiarity between the Makkan and Madinan Suwar of the Glorious Qur'an is that Makkan Suwar are short and poetic while the Madinan Suwar are longer and generic. The Makkan Suwar, revealed in Makkah, are generally shorter and more poetic, focusing on monotheism, morality, and the afterlife. The Madinan Suwar, revealed in Madinah, are generally longer and deal with social legislation and the Muslim community.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : DIFFERENCES BETWEEN MAKKAH AND MADINAN SUWAR"}, {"id": "objective>IRK>2010>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The copy of the Glorious Qur'an in use was standardized during the period of Caliph</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abu Bakr as Siddiq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Umar b. Khattab</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uthman b. Affan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ali b. Abu Talib</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The copy of the Glorious Qur'an in use was standardized during the period of Caliph Uthman b. Affan. During his caliphate, Uthman ordered the standardization of the Qur'anic text into the form used today, known as the 'Uthmanic codex'.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : RECORDING, COMPILATION AND STANDARDIZATION OF THE GLORIOUS QUR’AN"}, {"id": "objective>IRK>2010>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term Isra'iliyat in the study of tafsir refers to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">statements which refer to people of Israel in the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stories of the Israelites in the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">teachings concerning the Israelites in the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">traditions and commentaries with Jewish origin derived from nonmuslims sources</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Israiliyyat in the tafsir refers to traditions and commentaries with Jewish and commentraries with Jewish origin derived from non-muslim. </div>", "topic": "TAFSIR : IMPORTANCE AND TYPES OF TAFSIR"}, {"id": "objective>IRK>2010>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major themes that can be derived from Surah al-fatihah are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">knowledge, prayer and sacrifice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">praise, prayer and pledge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">praise, promise and equity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">praise, pledge and prayer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Q1:1-4 are praises of Allah  <br/>  Q1:5 is pledge  <br/>  Q1:6-7 are prayers for guidance.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-FATIHAH"}, {"id": "objective>IRK>2010>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse of the Glorious Qur'an above refers to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">back-biters </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rumour mongers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">envious ones </div>", "<div style=\"font-family:Cambria;font-size:17px;\">treasury looters</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qur'an 113:5: <br/> ---And from the evil of the envier when he envies.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -HUMAZAH"}, {"id": "objective>IRK>2010>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Al-Kawthar in the Glorious Qur'an is otherwise called a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">river in paradise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">garden in paradise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light in paradise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fruit in paradise</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Al-Kawthar is mentioned in the Quran in Surah Al-Kawthar. It is described as a river in Paradise that Allah granted to Prophet Muhammad.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -KAWTHAR"}, {"id": "objective>IRK>2010>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The significant message contained in surah at-Takathur is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">passion for wealth and position may divert man's attention from worship of Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moral obligation and spiritual sacrifice should be uppermost in the minds of a true believer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">man should avoid committing sin at all times</div>", "<div style=\"font-family:Cambria;font-size:17px;\">man should pray five times daily</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah At-Takathur warns about the distraction and diversion caused by the competition in increase of wealth and children. It emphasizes that the passion for wealth and position may divert man's attention from the worship of Allah.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : GENERAL MORAL LESSONS CONTAINED IN THE ADMONITION OF SAGE LUQMAN TO HIS SON"}, {"id": "objective>IRK>2010>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Day of Judgement is described in surah al-Qari'ah as a day when men will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">arranged in three rows</div>", "<div style=\"font-family:Cambria;font-size:17px;\">made to drink from hot vessels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">like moths scattered about</div>", "<div style=\"font-family:Cambria;font-size:17px;\">made to wear iron rods around their necks</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah Al-Qari'ah describes the Day of Judgement as a day when men will be like moths scattered about. This metaphor is used to depict the chaos and terror of that day.</div>", "topic": "ARTICLE OF FAITH : THE LAST DAY: YAWM-AL-BA'TH"}, {"id": "objective>IRK>2010>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above is translated as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">\"truly, man is to his Lord grateful\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"truly, man is too arrogant\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"truly, man is submissive\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"truly, man is to his Lord ungrateful\"</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qur'an 100:6: <br/> Indeed, mankind is ungrateful to his Lord.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -KAWTHAR"}, {"id": "objective>IRK>2010>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"Peace descending on the righteous throughout the night\". The verse above is one of the major themes in Surah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Qadr </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Alaq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Kawthar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Falaq</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse 'Peace descending on the righteous throughout the night' is one of the major themes in Surah Al-Qadr. This Surah talks about the night of Qadr (Decree) which is better than a thousand months. On this night, peace descends until the emergence of dawn.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-QADR"}, {"id": "objective>IRK>2010>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">18. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse of the Glorious Qur'an above is on the importance of knowledge and the description of Allah as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the Supreme</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the most Gracious</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Grand Teacher</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Grand Supplier</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">He has taught man what he knew not — knowledge from Allah. Q96:5 </div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : THE GLORIOUS QUR'AN AND HADITH ON EDUCATION"}, {"id": "objective>IRK>2010>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A text of Hadith is rejected if it is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reported by an Arab</div>", "<div style=\"font-family:Cambria;font-size:17px;\">against natural phenomenon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reported twice by the same reporter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not reported in Madinah</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Hadith is considered rejected if it contradicts established principles of the Quran or known facts, such as natural phenomena. This is because the Hadith, sayings and actions of Prophet Muhammad, are meant to align with the teachings of the Quran and reality. Therefore, if a Hadith is against natural phenomena, it is likely to be rejected.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2010>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 4 of An-Nawawi\"s collection is about the complete</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nature of man\"s creation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">movement of the sun in its orbit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of the creation of the earth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">movement of the seas and oceans</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Surely, the creation of everyone of you takes place in him mother's womb in 40 days in sperm\" </div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2010>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The book of Hadith that contains reports on the practices of the people of Madinah apart from ahadith is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sahih Bukhari </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sahih Muslim</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mukhtaril ahadith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muwatta Malik</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Muwatta Malik is a collection of Hadith compiled by Imam Malik. It is unique in that it includes not only Hadith of the Prophet Muhammad, but also the practices of the people of Madinah, providing a comprehensive view of the Islamic practices of the time.</div>", "topic": "HADITH : MUWATTA AND ITS AUTHOR – THE BIOGRAPHY OF IMAM MALIK AND THE STUDY OF HIS BOOK"}, {"id": "objective>IRK>2010>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Hadith 6 of an-Nawawi's collection, the Prophet (SAW) said the lawful and unlawful are all clear, but between them <br/> are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">things prohibited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">things permitted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ambiguous matters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lump of flesh</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Hadith 6 of An-Nawawi's collection, Prophet Muhammad (SAW) said that the lawful (halal) and unlawful (haram) are clear, but between them are ambiguous matters. These are matters that are not clearly defined as either lawful or unlawful.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2010>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong> \"Indeed the people before you were destroyed by asking a lot of unnecessary questions\". </strong>  <br/>  The quotation above is in Hadith 9 of An- Nawawi which refers to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">People of the Book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quraysh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">People of Madinah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arabs</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quotation is referring to the 'People of the Book', a term used in the Quran to refer to followers of previous scriptures, mainly Jews and Christians. The Hadith warns against excessive questioning and disputing about religious matters, which was a characteristic attributed to these groups.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2010>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Who among the six compilers of Hadith became blind before his death?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nasa'i </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abu Da'ud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibn Maja </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tirmidhi</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Imam Tirmidhi, one of the six compilers of Hadith, became blind before his death. This is a historical fact known in Islamic studies.</div>", "topic": "HADITH : THE SIX SOUND COLLECTORS OF HADITH – BIOGRAPHIES AND THEIR WORKS."}, {"id": "objective>IRK>2010>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">25. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The subject matter of the Hadith above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dignity of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">modesty in dressing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">honesty and sincerity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stealing and fraud</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Honesty and sincerity are key virtues in Islam and worship.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : DIGNITY OF LABOUR (Q.62:10) (Q.78:11) HADITH FROM BUKHARI AND IBNMAJAH: “THAT ONE OF YOU TAKES HIS ROPE…….” “NEVER HAS ANYONE OF YOU EATEN…..”."}, {"id": "objective>IRK>2010>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Q.17:27, the extravagant are likened to associates of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pious people </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pharaoh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">satan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soothsayers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Quran 17:27, the extravagant are likened to associates of Satan. The verse says, 'Indeed, the wasteful are brothers of the devils, and ever has Satan been to his Lord ungrateful.'</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>2010>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Islam decreed against begging through encouraging</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">collective bargaining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade bargaining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dignity of labour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Islam discourages begging and encourages the dignity of labour. This is because Islam promotes self-reliance, hard work, and earning a living through lawful means.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : DIGNITY OF LABOUR (Q.62:10) (Q.78:11) HADITH FROM BUKHARI AND IBNMAJAH: “THAT ONE OF YOU TAKES HIS ROPE…….” “NEVER HAS ANYONE OF YOU EATEN…..”."}, {"id": "objective>IRK>2010>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"Allah begets not nor is He begotten.\"  <br/>  The quotation above condemns</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hero praising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the doctrine of trinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">worshiping of ancestors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">idol worshiping</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quotation 'Allah begets not nor is He begotten' is a verse from the Quran (112:3) that condemns the Christian doctrine of trinity, which posits that God is three in one (Father, Son, and Holy Spirit) and that Jesus is the begotten son of God.</div>", "topic": "TAWHID AND FIQH : SHIRK"}, {"id": "objective>IRK>2010>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is expected of a believing Muslim when an important decision needs to be made?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Du'a </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Da'awah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Istikhama </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Istikharah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a Muslim needs to take a decision, he should do Istikharah (divine consultation with Allah) through prayer.</div>", "topic": "IBADAT AND THEIR TYPES : GOOD DEEDS 26TH HADITH OF AN-NAWAWI"}, {"id": "objective>IRK>2010>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Qadr to the majority of scholars in Islam means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">faith </div>", "<div style=\"font-family:Cambria;font-size:17px;\">situation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">circumstance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">destiny</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qadr in Islam refers to the concept of divine destiny. It is the belief that everything that happens in life, from good to bad, is preordained by Allah. Therefore, the correct answer is 'destiny'.</div>", "topic": "ARTICLE OF FAITH : DESTINY: DISTINCTION BETWEEN QADA AND QADAR"}, {"id": "objective>IRK>2010>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best Ibadah according to the Prophet (SAW) after the major pillars is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pray nawafils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marry a pious woman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make a fellow Muslim happy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">devote one's time on dhikr</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Hadiths, the Prophet Muhammad (SAW) emphasized the importance of making a fellow Muslim happy. This act is considered a significant form of Ibadah (worship) after the major pillars of Islam. Therefore, the correct answer is 'make a fellow Muslim happy'.</div>", "topic": "IBADAT AND THEIR TYPES : GOOD DEEDS 26TH HADITH OF AN-NAWAWI"}, {"id": "objective>IRK>2010>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Among the obligatory steps of ablution are intention, washing the face, washing the hands to the elbow and also</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rinsing the mouth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wiping the two ears</div>", "<div style=\"font-family:Cambria;font-size:17px;\">washing the feet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silence during the ablution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The obligatory steps of ablution (wudu) in Islam include intention (niyyah), washing the face, washing the hands up to the elbows, and washing the feet up to the ankles. Therefore, the correct answer is 'washing the feet'.</div>", "topic": "IBADAT AND THEIR TYPES : TAHARAH, ITS TYPES AND IMPORTANCE AL-ISTINJA'/ISTIJMAR, ALWUDU', AT-TAYAMMUM AND AL-GHUSL HADITH 10 AND 23 OF AN-NAWAWI"}, {"id": "objective>IRK>2010>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Among the Sunnah steps of ablution are wiping two ears, inhaling and exhaling from the nose and also</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wiping the head again from back of the skull</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supplication at every stage of ablution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brushing the teeth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saying the du'a aloud</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wiping the head from front to back is part of wudu in Islam.</div>", "topic": "IBADAT AND THEIR TYPES : TAHARAH, ITS TYPES AND IMPORTANCE AL-ISTINJA'/ISTIJMAR, ALWUDU', AT-TAYAMMUM AND AL-GHUSL HADITH 10 AND 23 OF AN-NAWAWI"}, {"id": "objective>IRK>2010>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Q.5:7, Allah says, \"if ye are ill or on a journey\" and ye find no water, then perform \"\"</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wuda </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-ghusl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at-tayammum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">qasr</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Q.5:7, Allah says, \"if ye are ill or on a journey\" and ye find no water, then perform At-Tayammum</div>", "topic": "IBADAT AND THEIR TYPES : TAHARAH, ITS TYPES AND IMPORTANCE AL-ISTINJA'/ISTIJMAR, ALWUDU', AT-TAYAMMUM AND AL-GHUSL HADITH 10 AND 23 OF AN-NAWAWI"}, {"id": "objective>IRK>2010>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of takbirat performed in a rak'ah as a unit of salah is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">7 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are 7 Takbeerāt in the first Rak'ah of Eid prayer.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2010>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An Imam leading prayer, forgetfully rises when he is to sit, he is alerted by saying</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">astaghfirullah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Allahu Akba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subhanallah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subhana rabbial Azim</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If an Imam leading prayer forgetfully rises when he is to sit, he is alerted by saying 'Subhanallah'. This is based on the Hadith of the Prophet Muhammad (peace be upon him) where he said that if something happens in the prayer, men should say 'Subhanallah' and women should clap their hands. Therefore, the correct option is 'Subhanallah'.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2010>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fasting has been prohibited on doubtful day which is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">28th of Sha'aban</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1st of Ramadan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30th of Ramada</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30th of Sha'aban</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fasting has been prohibited on the 'doubtful day' which is the 30th of Sha'aban. This is because it's uncertain whether it's the last day of Sha'aban or the first day of Ramadan. Therefore, to avoid confusion and possible error in starting the fast of Ramadan, it's recommended not to fast on this day. Hence, the correct option is '30th of Sha'aban'.</div>", "topic": "IBADAT AND THEIR TYPES : SAWM"}, {"id": "objective>IRK>2010>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Those who are not Pilgrims are advised to fast on the day of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eid al-fitri </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ashurah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eid al-adha </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arafat</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Those who are not pilgrims are advised to fast on the day of Arafat. The Prophet Muhammad (peace be upon him) said that fasting on the day of Arafat expiates the sins of the previous year and the coming year. Therefore, the correct option is 'Arafat'.</div>", "topic": "IBADAT AND THEIR TYPES : HAJJ"}, {"id": "objective>IRK>2010>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The permission to marry up to four wives in Islam is aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bearing more children</div>", "<div style=\"font-family:Cambria;font-size:17px;\">treating them equally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing the number of unmarried women</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preventing adultery</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is aimed at preventing adultery and preserving chastity.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2010>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Prophet (SAW) said, \"Of all things lawful, divorce is the most hateful to Allah\" because it exposes the parties to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reconciliation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provocation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hardship </div>", "<div style=\"font-family:Cambria;font-size:17px;\">arbitration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Talaq (divorce) may lead to conflicts and family provocation.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>2010>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Imam Malik was born in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Syria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Makkah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Madinah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Egypt</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Imam Malik, also known as Malik ibn Anas, was born in Madinah. He was a prominent Islamic scholar during his time and is best known for his work on Islamic jurisprudence (Fiqh) and Hadith.</div>", "topic": "HADITH : MUWATTA AND ITS AUTHOR – THE BIOGRAPHY OF IMAM MALIK AND THE STUDY OF HIS BOOK"}, {"id": "objective>IRK>2010>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Allah\"s pleasure in this world and the hereafter can be obtained through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">physical exercises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">writing Qur'an on a slate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shari'a</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oratory</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pleasure of Allah could be attained here and thereafter through and thereafter through total adherance to the Shariah.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2010>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lending out money with interest in Islam is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sadaqah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">riba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kharaj </div>", "<div style=\"font-family:Cambria;font-size:17px;\">jizyah</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lending out money with interest in Islam is referred to as 'riba'. Riba, or usury, is prohibited in Islam because it is considered exploitative. According to Islamic law, making money from money, such as charging interest, is not a legitimate, ethical, or fair form of business.</div>", "topic": "ISLAMIC ECONOMIC SYSTEM : ISLAMIC ATTITUDE TO RIBA HADITH 6TH OF AN-NAWAWI"}, {"id": "objective>IRK>2010>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zakat is an economic system that deemphasizes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accumulation of wealth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poverty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helping others</div>", "<div style=\"font-family:Cambria;font-size:17px;\">employment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zakat is an economic system in Islam that deemphasizes the accumulation of wealth. It is a form of almsgiving to the poor and needy that is religiously obligatory for all who are able to do so. It serves to purify one's wealth, encourage social harmony, and reduce inequality.</div>", "topic": "ISLAMIC ECONOMIC SYSTEM : ISLAMIC SOURCES OF REVENUE: ZAKAH, JIZYAH, KHARAJ AND GHANIMAH"}, {"id": "objective>IRK>2010>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"O Allah! Lord of power (and rule), Thou giveth power to whom thou pleaseth, and thou strippest off power from whom thou pleaseth\".  <br/>  The verse above describes Allah\"s political power as most</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">complex </div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">severe </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sovereign</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse describes Allah's political power as sovereign. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In the context of the verse, it means that Allah has the ultimate authority to give and take power as He pleases.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2010>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The core of Muhammad\"s (SAW) da'awah in Makkah was on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the unity of Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">business transaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">divine punishment of wrong-doers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sincere brotherhood</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The core of Prophet Muhammad's (SAW) da'awah (call to Islam) in Makkah was on the unity of Allah. This is known as Tawhid in Islamic theology, which asserts that Allah is one and unique.</div>", "topic": "TAWHID AND FIQH : KALIMATUSH-SHAHADAH"}, {"id": "objective>IRK>2010>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The battle of Badr was fought in the 2nd year after Hijrah in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">622 A.H.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">624 A.H.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">625 A.H </div>", "<div style=\"font-family:Cambria;font-size:17px;\">632 A.H.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Battle of Badr was fought in the 2nd year after Hijrah, which corresponds to 624 A.H. (After Hijrah). Hijrah is the migration of Prophet Muhammad (SAW) from Makkah to Madinah.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE BATTLES OF BADR, UHUD AND KHANDAQ: CAUSES AND EFFECTS"}, {"id": "objective>IRK>2010>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Arabs worshipped idols during the Jahiliyya period because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They were ignorant of God's existence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There were Prophets among them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They believed that the idols will intercede</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There were revealed Books</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Jahihyyah Arabs believed in Allah partially but they believed that the idols are intermidiaries (go between) between them and Allah.</div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : JAHILIYYAH PRACTICES: IDOL WORSHIP, INFANTICIDE, POLYANDRY, GAMBLING, USURY, ETC."}, {"id": "objective>IRK>2010>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The similarity between the Jihad of Uthman D. Fodio and the Prophet's hijrah in 622 C.E was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">strength of their followers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inspiration from Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">display of bid'ah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">envy of non-believers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The strength of their followers lies in unity and strong belief.</div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE ROLE OF TRADERS, TEACHERS, PREACHERS, MURABITUN, SUFI ORDERS AND MUJADDIDUN TO THE SPREAD OF ISLAM IN WEST AFRICA."}, {"id": "objective>IRK>2010>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The companion who introduced Islam to North Africa through Egypt was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Amr B. As </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abu Musa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibn Ishaq </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibn Suleiman</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amr B. As was the companion of Prophet Muhammad who introduced Islam to North Africa through Egypt. He was a military commander and statesman, who led the Muslim conquest of Egypt in 640 AD.</div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE SPREAD OF ISLAM TO EGYPT"}];
